  animation: highlight-fade 2s ease-out;
}

@keyframes highlight-fade {
  0% { background-color: #fff3cd; }
  100% { background-color: transparent; }
}

/* 좋아요 통계 행 */
.like-stats-row {
  display: flex;
  align-items: center;
  gap: 12px;
}

.view-details-btn {
  background: none;
  border: none;
  color: var\(--primary-color\);
  font-size: 13px;
  cursor: pointer;
  text-decoration: underline;
  padding: 0;
}

.view-details-btn:hover {
  color: var\(--primary-hover\);
}

.view-details-btn:active {
  transform: scale\(0.95\);
}

/* 좋아요 상세 모달 */
.like-stats-modal {
  max-width: 400px;
  width: 90%;
}

.total-likes {
  font-size: 16px;
  font-weight: 600;
  color: var\(--text-primary\);
  margin-bottom: 16px;
  text-align: center;
}

.like-stat-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.like-stat-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px;
  background: var\(--input-bg\);
  border-radius: 8px;
}

.club-logo-small {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  object-fit: cover;
}

.club-logo-placeholder {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var\(--gradient-primary\);
  color: white;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 14px;
  font-weight: 600;
}

.like-stat-item .club-name {
  flex: 1;
  font-size: 14px;
  font-weight: 500;
  color: var\(--text-primary\);
}

.like-stat-item .like-count {
  font-size: 14px;
  font-weight: 600;
  color: var\(--primary-color\);
}

/* 통합 댓글 섹션 */
.integrated-comment-section {
  margin-top: 8px;
}

.detail-section.full-width {
  grid-column: 1 / -1;
}
